-- W1.6 questions batch 4895/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6e2f88c7-moex-00142', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲主張其為A屋所有人，將A屋出租於乙，惟甲、乙之租約已到期，且乙
於租約到期後仍住A屋長達2年。甲遂以乙為被告，列先、備位請求為，先
位請求：請求乙返還租賃物A屋，並給付相當於兩年房租租金之不當得利
共計新臺幣（下同）200萬元。備位請求：請求乙返還所有物A屋，並給付
其損害所有權之賠償共計200萬元。乙於第一審準備程序時，向法院提出
主張謂，甲並非A屋所有人，該A屋為乙另向真正所有人丙（即甲之配偶）
承租。且乙、丙曾以手機簡訊同意租期為5年，乙並有手機截圖為證。同
時，乙提出反訴，主張甲應為該濫訴致生毀損乙之名譽，給付其精神損害
賠償200萬元。試問：審判長就本件當事人甲、乙所提出之各項主張，應
進行如何之闡明，並指揮爭點整理程序？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00143', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲具有原住民身分，涉犯殺人罪。偵查中，檢察官依法通知法律扶助基金
會指派律師乙擔任甲的辯護人，並向法院聲請羈押甲。羈押審查程序期
日，乙沒有到場且無法取得聯繫。請問：根據刑事訴訟法，法院能否在乙
缺席下審查對甲的羈押聲請？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00144', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲因為普通強盜罪遭檢察官起訴。案件經合法提起上訴並由第二審法院
受理，甲依法選任其妻乙擔任輔佐人。審判期日，乙因為與甲吵架未到場，
法院多方嘗試聯繫，乙卻不接電話且對文字訊息也是「已讀不回」。審判
長丙隨即開始審判程序並作成判決。甲以第二審判決在乙缺席下作成，對
最高法院提起上訴。請問：按照刑事訴訟法，最高法院應否根據甲的上訴
開啟審判程序？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00145', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲乙原為夫妻，育有未成年子女丙，嗣後甲、乙感情生變離婚後，共同約
定將丙事實上之保護教養事項，委由甲之母親丁監護。丙於青春期時學
壞，在外參加幫派屢涉非行，丁年紀大深覺無力管教，而欲終止該委託，
惟當時甲已死亡，乙已經再婚不願再管丙的事。試問：甲乙當時與丁所約
定之契約性質為何？丁得否終止與乙之契約關係？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00146', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲與其孫乙簽訂贈與契約書，將其所有不動產贈與乙，並約定甲贈與不動
產於乙，且乙應扶養甲，嗣後乙又將此債權轉讓於丙，甲於尚未辦理所有
權移轉登記前突然死亡，甲之繼承人為丁戊等二人，試問：乙或丙得否請
求甲之繼承人丁戊履行原本甲應負移轉該不動產所有權之義務？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00147', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲乙丙三人為A法人之董事，約定僅甲乙有對外代表權，甲之權限為人事招聘，乙之權限為人事 以外之綜合事務。下列敘述，何者正確？', '["該代表權限制之約定得對抗任何第三人", "丙就法人一切事務，對外代表法人之限制，須以章程為之", "甲乙對外代表為人事招聘或綜合事務之權限區分，須以章程為之", "此等對丙之對外代表權限之限制，若未以章程為之，不得對抗善意第三人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00148', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲為A屋之所有人，下列關於A屋之買賣契約，何者無效？', '["甲乙訂立買賣A屋之契約，卻均不知A屋已經於該買賣契約締結之前夕，因火災而片瓦不留", "甲將A屋出租於乙，其後將A屋出賣於丙", "乙明知A屋為甲所有，卻將A屋出賣於知情之丙", "甲先將A屋出賣於乙，又將A屋出賣於丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00149', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於民法第107條代理權限制及撤回之敘述，何者錯誤？', '["第三人因過失而不知其事實者，本人不得以代理權之限制及撤回對抗之", "本條亦可能構成表見代理", "相對人如不主張表見代理，則依無權代理之規定處理", "相對人明知無權代理人無代理權，或依情形可得而知，而仍與其為法律行為，則本人不負授權 人之責任 32820、33320 33620"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00150', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '依民法規定，下列關於時效中斷效力之敘述，何者錯誤？', '["時效因請求而中斷者，其意思表示於相對人所了解或到達相對人時，時效期間重行起算", "時效因起訴而中斷者，自受確定判決時，時效期間重行起算", "時效因聲請發支付命令而中斷者，自受支付命令之裁定確定時，時效期間重行起算", "經假執行裁定所確定之請求權，其原有消滅時效期間不滿5年者，因中斷而重行起算之時效期間 為5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00151', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲與其配偶乙報名丙旅行社所主辦之櫻花之旅，但行前乙臨時身體不適，向丙請求改由自己已退 休多年之父丁參加旅遊。丁是高齡者，可以減少旅行途中之交通費以及門票等費用，乙便請求丙 退還減少之部分，丙不許。出發到當地，甲發現櫻花根本還沒有開，憤而要求終止契約，丁則繼 續參加完行程，但全程都沒看到櫻花。下列敘述，何者正確？', '["乙於旅遊開始即變更由丁參加旅遊，因此減少之費用，得請求退還", "甲依民法第514條之7規定，終止契約時，丙應將甲送回原出發地，其所生之費用，由甲負擔", "丁雖然全程參加完行程，但沒看到櫻花時，若可歸責於丙，而不具備旅遊服務之品質，則丁得 向丙請求減少費用", "旅遊完成後，旅客得隨時終止契約，但應賠償旅遊營業人因契約終止而生之損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
